"use client";

/* ════════════════════════════════════════════════════════════════════════
   BridgeNewItem — write surface for creating a SKU.
   Ported from /Users/mac/Downloads/MAGELLAN UX/Bridge/Opertation/
   magellan-bridge-new-item.html

   Modes:
   - Single — drop zone + form + live consequence read (3 tiers)
   - Batch  — drop a CSV / Excel, review N rows (v1: stubbed drop zone only)

   For "Composed" type, the cost rolls up from components and adds a
   "Build truth — theoretical vs actual" tier to the consequence read.
   ════════════════════════════════════════════════════════════════════════ */

import { useMemo, useState } from "react";
import { useBridge } from "@/features/bridge/hooks/use-bridge";

type ItemType = "stocked" | "composed" | "mto";
type Mode = "single" | "batch";

const CATEGORIES = [
  "Bouquets",
  "Arrangements",
  "Plants",
  "Cakes",
  "Chocolates",
  "Gift Baskets",
  "Add-ons",
  "Materials & Components",
];

const SUPPLIERS = [
  { name: "Kunming Flowers", lead: 7 },
  { name: "Nordic Floral", lead: 2 },
  { name: "Belgian Cocoa Co.", lead: 14 },
  { name: "Apex Supplies", lead: 5 },
  { name: "Local Market", lead: 0 },
];

const fmtUSD = (v: number) =>
  v >= 1000 ? `$${(v / 1000).toFixed(v >= 10000 ? 0 : 1)}K` : `$${Math.round(v)}`;

export function BridgeNewItem() {
  const { setPage } = useBridge();

  const [mode, setMode] = useState<Mode>("single");
  const [type, setType] = useState<ItemType>("stocked");

  // Single-mode form state
  const [name, setName] = useState("");
  const [category, setCategory] = useState<string | null>(null);
  const [supplier, setSupplier] = useState<{ name: string; lead: number } | null>(null);

  // Cost build (Stocked)
  const [unitCost, setUnitCost] = useState("");
  const [freight, setFreight] = useState("");
  const [duty, setDuty] = useState("");
  const [handling, setHandling] = useState("");

  const [price, setPrice] = useState("");
  const [stock, setStock] = useState("");

  const [openMenu, setOpenMenu] = useState<"category" | "supplier" | null>(null);
  const [created, setCreated] = useState(false);

  const num = (s: string) => {
    const n = parseFloat(s.replace(/[^0-9.-]/g, ""));
    return isNaN(n) ? 0 : n;
  };

  // Computed values
  const landed = num(unitCost) + num(freight) + num(duty) + num(handling);
  const priceN = num(price);
  const stockN = num(stock);
  const cm1Pct = priceN > 0 ? Math.round(((priceN - landed) / priceN) * 100) : 0;
  const cm1Abs = priceN - landed;

  const leadDays = supplier?.lead ?? 0;
  // Heuristic velocity: depends on category — use a friendly default
  const velocity = category === "Materials & Components" ? 2 : 4; // units/day demo
  const safetyStock = Math.ceil(velocity * 2); // 2-day safety
  const reorderPoint = leadDays > 0 ? Math.ceil(velocity * leadDays + safetyStock) : 0;
  const daysOfCover = velocity > 0 ? Math.round(stockN / velocity) : 0;
  const capitalLocked = stockN * landed;
  const reorderCycle = leadDays > 0 ? `${leadDays + Math.round(stockN / velocity)}d` : "—";
  const nextPOExposure = reorderPoint > 0 ? fmtUSD((reorderPoint + safetyStock) * landed) : "—";

  const enoughFilled = useMemo(() => {
    const filled = [name, category, supplier, unitCost, price, stock].filter(Boolean).length;
    return filled >= 4;
  }, [name, category, supplier, unitCost, price, stock]);

  const create = () => {
    setCreated(true);
    setTimeout(() => {
      setCreated(false);
      setPage("home");
    }, 1600);
  };

  return (
    <div className="bridge-content">
      <div className="bridge-page-head">
        <div className="bridge-page-head-icon">
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round">
            <path d="M12 2 L21 7 L21 17 L12 22 L3 17 L3 7 Z" />
            <path d="M3 7 L12 12 L21 7" />
            <line x1="12" y1="12" x2="12" y2="22" />
          </svg>
        </div>
        <div>
          <div className="bridge-page-head-title">New Item</div>
          <div className="bridge-page-head-sub">
            Drop a file and Magellan fills it in — you review the landed cost and reorder point, then confirm.
          </div>
        </div>
      </div>

      {/* Mode toggle */}
      <div className="bridge-ni-mode">
        <button
          className={`bridge-ni-mode-btn${mode === "single" ? " on" : ""}`}
          onClick={() => setMode("single")}
          type="button"
        >
          Single item
        </button>
        <button
          className={`bridge-ni-mode-btn${mode === "batch" ? " on" : ""}`}
          onClick={() => setMode("batch")}
          type="button"
        >
          Batch — from a sheet
        </button>
      </div>

      {mode === "batch" ? (
        <>
          <div className="bridge-ni-drop">
            <div className="bridge-ni-drop-icon">
              <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.7" strokeLinecap="round" strokeLinejoin="round">
                <path d="M12 16 L12 4 M12 4 L8 8 M12 4 L16 8" />
                <path d="M4 14 L4 19 A1 1 0 0 0 5 20 L19 20 A1 1 0 0 0 20 19 L20 14" />
              </svg>
            </div>
            <div className="bridge-ni-drop-text">
              <div className="bridge-ni-drop-title">
                Drop a supplier sheet — create many items at once
              </div>
              <div className="bridge-ni-drop-sub">
                CSV or Excel. Magellan reads every row, builds the landed cost and reorder point for each, and lays them out for review.
              </div>
            </div>
            <button className="bridge-ni-drop-browse" type="button">Choose sheet</button>
          </div>
          <div className="bridge-ni-commit">
            <div className="bridge-ni-commit-note">
              Batch review table appears here once a sheet is read — only <b>ready</b> rows go live on commit.
            </div>
            <div className="bridge-ni-commit-btns">
              <button className="bridge-ni-cancel" type="button" onClick={() => setPage("home")}>
                Cancel
              </button>
            </div>
          </div>
        </>
      ) : (
        <>
          {/* Drop to fill */}
          <div className="bridge-ni-drop">
            <div className="bridge-ni-drop-icon">
              <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.7" strokeLinecap="round" strokeLinejoin="round">
                <path d="M12 16 L12 4 M12 4 L8 8 M12 4 L16 8" />
                <path d="M4 14 L4 19 A1 1 0 0 0 5 20 L19 20 A1 1 0 0 0 20 19 L20 14" />
              </svg>
            </div>
            <div className="bridge-ni-drop-text">
              <div className="bridge-ni-drop-title">
                Drop a product photo, supplier sheet, or receipt — or fill it in below
              </div>
              <div className="bridge-ni-drop-sub">
                Magellan reads the file and fills the fields for you. Everything stays editable.
              </div>
            </div>
            <button className="bridge-ni-drop-browse" type="button">Choose file</button>
          </div>

          {/* The item card */}
          <div className="bridge-ni-card">
            <div className="bridge-ni-card-head">
              <span className="bridge-ni-section">The item</span>
              <span className="bridge-ni-source manual">✏ Entering manually</span>
            </div>
            <div className="bridge-ni-grid">
              <div className="bridge-ni-field bridge-ni-span">
                <span className="bridge-ni-label">Item name</span>
                <input
                  className="bridge-ni-input"
                  type="text"
                  placeholder="e.g. Pastel Tulip Bouquet"
                  value={name}
                  onChange={(e) => setName(e.target.value)}
                />
              </div>

              <div className="bridge-ni-field">
                <span className="bridge-ni-label">Category</span>
                <div
                  className={`bridge-ni-select${openMenu === "category" ? " open" : ""}`}
                  onClick={() => setOpenMenu((m) => (m === "category" ? null : "category"))}
                >
                  <span className={category ? "" : "ph"}>{category ?? "Choose category"}</span>
                  <span className="chev">▾</span>
                  {openMenu === "category" && (
                    <div className="bridge-ni-menu open">
                      {CATEGORIES.map((c) => (
                        <div
                          key={c}
                          className="bridge-ni-menu-item"
                          onClick={(e) => {
                            e.stopPropagation();
                            setCategory(c);
                            setOpenMenu(null);
                          }}
                        >
                          {c}
                        </div>
                      ))}
                    </div>
                  )}
                </div>
              </div>

              <div className="bridge-ni-field">
                <span className="bridge-ni-label">Type</span>
                <div className="bridge-ni-seg">
                  <button className={type === "stocked" ? "on" : ""} onClick={() => setType("stocked")} type="button">Stocked</button>
                  <button className={type === "composed" ? "on" : ""} onClick={() => setType("composed")} type="button">Composed</button>
                  <button className={type === "mto" ? "on" : ""} onClick={() => setType("mto")} type="button">Made-to-order</button>
                </div>
              </div>

              <div className="bridge-ni-field bridge-ni-span">
                <span className="bridge-ni-label">Supplier</span>
                <div
                  className={`bridge-ni-select${openMenu === "supplier" ? " open" : ""}`}
                  onClick={() => setOpenMenu((m) => (m === "supplier" ? null : "supplier"))}
                >
                  <span className={supplier ? "" : "ph"}>{supplier?.name ?? "Choose supplier"}</span>
                  {supplier && <span className="meta">{supplier.lead}d lead</span>}
                  <span className="chev">▾</span>
                  {openMenu === "supplier" && (
                    <div className="bridge-ni-menu open">
                      {SUPPLIERS.map((s) => (
                        <div
                          key={s.name}
                          className="bridge-ni-menu-item"
                          onClick={(e) => {
                            e.stopPropagation();
                            setSupplier(s);
                            setOpenMenu(null);
                          }}
                        >
                          {s.name}
                          <span className="sub">{s.lead}d lead</span>
                        </div>
                      ))}
                    </div>
                  )}
                </div>
              </div>

              {/* Cost build — Stocked vs Composed */}
              {type !== "composed" ? (
                <div className="bridge-ni-cost">
                  <div className="bridge-ni-cost-head">
                    <span className="bridge-ni-label">Landed cost build</span>
                    <span className="bridge-ni-cost-note">the only cost the room speaks</span>
                  </div>
                  <div className="bridge-ni-cost-row">
                    <span>Supplier unit cost</span>
                    <input
                      className="bridge-ni-num"
                      type="text"
                      placeholder="0"
                      value={unitCost}
                      onChange={(e) => setUnitCost(e.target.value)}
                    />
                  </div>
                  <div className="bridge-ni-cost-row add">
                    <span>+ Freight</span>
                    <input
                      className="bridge-ni-num"
                      type="text"
                      placeholder="0"
                      value={freight}
                      onChange={(e) => setFreight(e.target.value)}
                    />
                  </div>
                  <div className="bridge-ni-cost-row add">
                    <span>+ Duty</span>
                    <input
                      className="bridge-ni-num"
                      type="text"
                      placeholder="0"
                      value={duty}
                      onChange={(e) => setDuty(e.target.value)}
                    />
                  </div>
                  <div className="bridge-ni-cost-row add">
                    <span>+ Handling</span>
                    <input
                      className="bridge-ni-num"
                      type="text"
                      placeholder="0"
                      value={handling}
                      onChange={(e) => setHandling(e.target.value)}
                    />
                  </div>
                  <div className="bridge-ni-cost-total">
                    <span className="lbl">Landed cost</span>
                    <span className="bridge-ni-landed">${landed.toFixed(landed < 100 ? 2 : 0)}</span>
                  </div>
                </div>
              ) : (
                <div className="bridge-ni-cost">
                  <div className="bridge-ni-cost-head">
                    <span className="bridge-ni-label">Build structure</span>
                    <span className="bridge-ni-cost-note">cost rolls up from components — not typed</span>
                  </div>
                  <div className="bridge-ni-bs-rows">
                    <div className="bridge-ni-bs-row">
                      <span className="bs-qty">6×</span>
                      <span className="bs-name">Component</span>
                      <span className="bs-kind">component</span>
                      <span className="bs-cost">$0</span>
                      <button className="bs-x" type="button" aria-label="Remove">×</button>
                    </div>
                  </div>
                  <button className="bridge-ni-bs-add" type="button">
                    + Add component or packaging
                  </button>
                  <div className="bridge-ni-cost-total">
                    <span className="lbl">
                      Rolled-up cost <span className="bs-labor">incl. $0 labor</span>
                    </span>
                    <span className="bridge-ni-landed">$0</span>
                  </div>
                </div>
              )}

              <div className="bridge-ni-field">
                <span className="bridge-ni-label">Selling price</span>
                <input
                  className="bridge-ni-input"
                  type="text"
                  placeholder="$0"
                  value={price}
                  onChange={(e) => setPrice(e.target.value)}
                />
              </div>
              <div className="bridge-ni-field">
                <span className="bridge-ni-label">Opening stock</span>
                <input
                  className="bridge-ni-input"
                  type="text"
                  placeholder="0 units"
                  value={stock}
                  onChange={(e) => setStock(e.target.value)}
                />
              </div>
            </div>
          </div>

          {/* What this creates */}
          <div className="bridge-ni-outcome">
            <div className="bridge-ni-outcome-head">
              <span className="m-mark">M</span> What this creates
              <span className={`bridge-ni-outcome-prov${enoughFilled ? " firm" : ""}`}>
                {enoughFilled ? "Computed from your inputs" : "Inferred — fill the fields to firm up"}
              </span>
            </div>

            <div className="bridge-ni-outcome-tier">
              <div className="bridge-ni-tier-label">Margin</div>
              <div className="bridge-ni-outcome-grid">
                <div className="bridge-ni-out">
                  <span className="k">Landed cost</span>
                  <span className="v">{landed > 0 ? `$${landed.toFixed(landed < 100 ? 2 : 0)}` : "—"}</span>
                  <span className="kk">supplier + freight + duty + handling</span>
                </div>
                <div className="bridge-ni-out">
                  <span className="k">CM1 per unit</span>
                  <span className={`v${cm1Pct >= 50 ? " good" : cm1Pct > 0 && cm1Pct < 30 ? " alert" : ""}`}>
                    {priceN > 0 && landed > 0 ? `${cm1Pct}%` : "—"}
                  </span>
                  <span className="kk">{priceN > 0 && landed > 0 ? `${fmtUSD(cm1Abs)} per unit` : "after landed"}</span>
                </div>
                <div className="bridge-ni-out">
                  <span className="k">Reorder point</span>
                  <span className="v">{reorderPoint > 0 ? `${reorderPoint} u` : "—"}</span>
                  <span className="kk">velocity × lead + safety</span>
                </div>
                <div className="bridge-ni-out">
                  <span className="k">Days of cover</span>
                  <span className="v">{daysOfCover > 0 ? `${daysOfCover}d` : "—"}</span>
                  <span className="kk">opening stock at velocity</span>
                </div>
              </div>
            </div>

            {type === "composed" && (
              <div className="bridge-ni-outcome-tier">
                <div className="bridge-ni-tier-label">Build truth — theoretical vs actual</div>
                <div className="bridge-ni-outcome-grid">
                  <div className="bridge-ni-out">
                    <span className="k">Theoretical cost</span>
                    <span className="v">$0</span>
                    <span className="kk">what the build says</span>
                  </div>
                  <div className="bridge-ni-out">
                    <span className="k">Actual consumed</span>
                    <span className="v">$0</span>
                    <span className="kk">last 30 days, per unit</span>
                  </div>
                  <div className="bridge-ni-out">
                    <span className="k">Shrink</span>
                    <span className="v">—</span>
                    <span className="kk">waste · substitution · overuse</span>
                  </div>
                  <div className="bridge-ni-out">
                    <span className="k">Margin lost to shrink</span>
                    <span className="v">—</span>
                    <span className="kk">of CM1</span>
                  </div>
                </div>
              </div>
            )}

            <div className="bridge-ni-outcome-tier">
              <div className="bridge-ni-tier-label">Capital &amp; runway</div>
              <div className="bridge-ni-outcome-grid">
                <div className="bridge-ni-out">
                  <span className="k">Capital locked now</span>
                  <span className="v">{capitalLocked > 0 ? fmtUSD(capitalLocked) : "—"}</span>
                  <span className="kk">opening stock × landed</span>
                </div>
                <div className="bridge-ni-out">
                  <span className="k">Inventory lifespan</span>
                  <span className="v">{daysOfCover > 0 ? `${Math.round((daysOfCover / 30) * 10) / 10}mo` : "—"}</span>
                  <span className="kk">at current velocity</span>
                </div>
                <div className="bridge-ni-out">
                  <span className="k">Reorder cycle</span>
                  <span className="v">{reorderCycle}</span>
                  <span className="kk">order-to-order</span>
                </div>
                <div className="bridge-ni-out">
                  <span className="k">Next PO exposure</span>
                  <span className="v">{nextPOExposure}</span>
                  <span className="kk">one reorder</span>
                </div>
              </div>
            </div>

            <div className="bridge-ni-outcome-note">
              <b>Reorder point</b> = category velocity × supplier lead time + safety stock. CM1 is computed on <b>landed cost</b>, not the invoice. Once created, this SKU appears in <b>Inventory Ledger</b>, <b>Categories</b> (capital share), and <b>Velocity</b>.
            </div>
          </div>

          {/* Commit */}
          <div className="bridge-ni-commit">
            <div className="bridge-ni-commit-note">
              This drafts the SKU — <b>nothing goes live</b> until you confirm. Reversible.
            </div>
            <div className="bridge-ni-commit-btns">
              <button className="bridge-ni-cancel" type="button" onClick={() => setPage("home")}>
                Cancel
              </button>
              <button
                className={`bridge-ni-create${created ? " done" : ""}`}
                type="button"
                onClick={create}
                disabled={!enoughFilled || created}
              >
                {created ? "Item drafted ✓" : "Create item →"}
              </button>
            </div>
          </div>
        </>
      )}
    </div>
  );
}
